// ExecuteBeadResult captures the outcome of an execute-bead worker run.
// The worker populates the task-level fields (BeadID through UsageFile).
// The parent orchestrator (LandBeadResult) populates the landing fields
// (Outcome, Status, Detail, Reason, PreserveRef, GateResults, RequiredExecSummary,
// ChecksFile) via ApplyLandingToResult before the result is written to disk or
// returned to a caller.
type ExecuteBeadResult struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	BaseRev   string `json:"base_rev"`
	ResultRev string `json:"result_rev,omitempty"`
	// ImplementationRev is the worker's own commit SHA — the candidate revision
	// produced by the agent before landing. Set from ResultRev by
	// ApplyLandResultToExecuteBeadResult before ResultRev is rewritten to the
	// branch tip. Never overwritten after first assignment.
	ImplementationRev string `json:"implementation_rev,omitempty"`
	// LandedRev is the target branch tip after the coordinator fast-forwards or
	// merges the implementation commit. Populated by ApplyLandResultToExecuteBeadResult.
	LandedRev string `json:"landed_rev,omitempty"`
	// TargetBranch is the resolved branch that received the landing. It uses the
	// landed_branch JSON name because callers care about the post-land location.
	TargetBranch string `json:"landed_branch,omitempty"`
	// EvidenceRev is the SHA of the trailing evidence commit when it differs from
	// ImplementationRev. Populated by the evidence committer; empty otherwise.
	EvidenceRev string `json:"evidence_rev,omitempty"`

	// Outcome and Status are initially set by the worker to task-level values
	// (task_succeeded / task_failed / task_no_changes), then overwritten by
	// ApplyLandingToResult with the landing decision (merged / preserved /
	// no-changes) so callers see a unified record.
	Outcome string `json:"outcome"`
	Status  string `json:"status,omitempty"`
	Detail  string `json:"detail,omitempty"`
	// OrchestratorStatus is populated after the landing/pre-merge orchestration
	// decision so result.json can distinguish worker success from final
	// non-landing outcomes.
	OrchestratorStatus string `json:"orchestrator_status,omitempty"`

	// Landing fields — populated by ApplyLandingToResult, not by ExecuteBead.
	Reason      string `json:"reason,omitempty"`
	PreserveRef string `json:"preserve_ref,omitempty"`
	// CandidateRef is the project-root git ref pinned before checks and review.
	// Format: refs/ddx/iterations/<attempt-id>/<cycle-index>.
	CandidateRef string `json:"candidate_ref,omitempty"`
	// CycleIndex is the zero-based repair-cycle index for this candidate.
	CycleIndex          int               `json:"cycle_index,omitempty"`
	GateResults         []GateCheckResult `json:"gate_results,omitempty"`
	RequiredExecSummary string            `json:"required_exec_summary,omitempty"`
	ChecksFile          string            `json:"checks_file,omitempty"`
	// Ratchet fields — populated by ApplyLandingToResult when declarative
	// ratchet thresholds were evaluated during landing. HELIX and other
	// consumers use these to distinguish ratchet-preserved attempts from
	// generic execution failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`

	// NoChangesRationale is populated when the agent wrote a rationale file to
	// the execution bundle dir inside the worktree. It carries the agent's
	// explanation of why no commits were made, and is preserved even when a
	// mixed commit + no_changes rationale is rejected.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`

	// NoEvidencePaths names worktree paths that remained dirty when the agent
	// exited without creating a commit or no_changes_rationale.txt. It helps
	// operators diagnose silent commit failures before the worktree is cleaned up.
	NoEvidencePaths []string `json:"no_evidence_paths,omitempty"`

	// CycleTrace records the append-only execution cycle trace in order.
	// Each entry captures one implementation or repair cycle.
	CycleTrace []ExecutionCycleTrace `json:"cycle_trace,omitempty"`

	// ResourceExhausted captures the root and cleanup summary when execution
	// stopped before a bead attempt because the host could not safely continue.
	ResourceExhausted any `json:"resource_exhausted,omitempty"`

	Harness                     string  `json:"harness,omitempty"`
	Provider                    string  `json:"provider,omitempty"`
	Model                       string  `json:"model,omitempty"`
	ActualPower                 int     `json:"actual_power,omitempty"`
	PredictedPower              int     `json:"predicted_power,omitempty"`
	PredictedSpeedTPS           float64 `json:"predicted_speed_tps,omitempty"`
	PredictedCostUSDPer1kTokens float64 `json:"predicted_cost_usd_per_1k_tokens,omitempty"`
	PredictedCostSource         string  `json:"predicted_cost_source,omitempty"`
	SessionID                   string  `json:"session_id,omitempty"`
	DurationMS                  int     `json:"duration_ms"`
	Tokens                      int     `json:"tokens,omitempty"`
	CostUSD                     float64 `json:"cost_usd,omitempty"`
	ExitCode                    int     `json:"exit_code"`
	Error                       string  `json:"error,omitempty"`
	ProjectRoot                 string  `json:"project_root,omitempty"`

	// FailureMode classifies why an execution did not land cleanly. Empty
	// when the bead was merged (task_succeeded landing outcome). Populated
	// by the orchestrator from known patterns; see ClassifyFailureMode and
	// the FailureMode* constants in execute_bead_status.go.
	FailureMode string `json:"failure_mode,omitempty"`

	ExecutionDir       string             `json:"execution_dir,omitempty"`
	PromptFile         string             `json:"prompt_file,omitempty"`
	ManifestFile       string             `json:"manifest_file,omitempty"`
	ResultFile         string             `json:"result_file,omitempty"`
	UsageFile          string             `json:"usage_file,omitempty"`
	WorktreePath       string             `json:"worktree_path,omitempty"`
	AttemptDiagnostics *AttemptDiagnostic `json:"attempt_diagnostics,omitempty"`
	Stderr             string             `json:"stderr,omitempty"`
	RateLimitBudget    time.Duration      `json:"rate_limit_budget,omitempty"`

	StartedAt  time.Time `json:"started_at"`
	FinishedAt time.Time `json:"finished_at"`
}

// ExecutionCycleRouteFacts captures the implementer-side routing facts for
// one execution cycle.
type ExecutionCycleRouteFacts struct {
	Harness         string `json:"harness,omitempty"`
	Provider        string `json:"provider,omitempty"`
	Model           string `json:"model,omitempty"`
	ActualPower     int    `json:"actual_power,omitempty"`
	RouteReason     string `json:"route_reason,omitempty"`
	ResolvedBaseURL string `json:"resolved_base_url,omitempty"`
}

// ExecutionCycleReviewResult captures the reduced review outcome for one
// execution cycle.
type ExecutionCycleReviewResult struct {
	Verdict        string     `json:"verdict,omitempty"`
	Rationale      string     `json:"rationale,omitempty"`
	Classification string     `json:"classification,omitempty"`
	PerAC          []ReviewAC `json:"per_ac,omitempty"`
	Findings       []Finding  `json:"findings,omitempty"`
}

// ExecutionCycleTrace records one implementation or repair cycle and its
// durable review/final-decision metadata.
type ExecutionCycleTrace struct {
	CycleIndex       int                        `json:"cycle_index"`
	AttemptID        string                     `json:"attempt_id,omitempty"`
	ResultRev        string                     `json:"result_rev,omitempty"`
	ImplementerRoute ExecutionCycleRouteFacts   `json:"implementer_route"`
	ReviewGroupID    string                     `json:"review_group_id,omitempty"`
	ReviewerIndices  []int                      `json:"reviewer_indices,omitempty"`
	ReviewVerdicts   []string                   `json:"review_verdicts,omitempty"`
	ReviewResult     ExecutionCycleReviewResult `json:"review_result,omitempty"`
	FinalDecision    string                     `json:"final_decision,omitempty"`
}

// AttemptDiagnostic captures infrastructure state when an attempt cannot be
// inspected normally. It is intentionally small and JSON-native so result.json
// remains useful even when the worker worktree has already vanished.
type AttemptDiagnostic struct {
	BeadID                 string    `json:"bead_id"`
	AttemptID              string    `json:"attempt_id"`
	WorktreePath           string    `json:"worktree_path"`
	HeadRevError           string    `json:"head_rev_error,omitempty"`
	WorktreePathExists     bool      `json:"worktree_path_exists"`
	CleanupMetadataPresent bool      `json:"cleanup_metadata_present"`
	RunStatePresent        bool      `json:"run_state_present"`
	RunState               *RunState `json:"run_state,omitempty"`
	GitWorktreeRegistered  bool      `json:"git_worktree_registered"`
}

// BeadEventAppender records append-only evidence events on a bead.
// Implemented by *bead.Store — kept as a minimal interface so the agent
// package does not need to import a concrete store type in tests.
type BeadEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

func appendWorkEvent(store BeadEventAppender, beadID, kind, summary string, body map[string]any, actor string, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	encodedBody, err := json.Marshal(body)
	if err != nil {
		return
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      kind,
		Summary:   summary,
		Body:      string(encodedBody),
		Actor:     actor,
		Source:    "ddx work",
		CreatedAt: at,
	})
}

// BeadCancelStore reads/writes the cancel markers on a bead's Extra map.
// Implemented by *bead.Store. ADR-022 §Cancel SLA: the worker polls
// IsCancelRequested mid-attempt and on a positive read writes
// MarkCancelHonored before aborting at the next safe point.
type BeadCancelStore interface {
	IsCancelRequested(id string) (bool, error)
	MarkCancelHonored(id string) error
}

// CancelPollInterval is how often the worker checks for an operator cancel
// while an agent attempt is in flight. ADR-022 §Cancel SLA names 10s as the
// default. Exposed as a variable so tests can override it.
var CancelPollInterval = 10 * time.Second

// RunStateRefreshInterval controls how often execute-bead refreshes its
// per-attempt liveness record while the agent harness is running. Exposed as a
// variable so tests can shorten it without slowing production attempts.
var RunStateRefreshInterval = 10 * time.Second

// ExecuteBeadRuntime carries the non-durable plumbing for an execute-bead
// run: per-invocation intent (FromRev, PromptFile, WorkerID) and
// non-serializable injection seams (BeadEvents, Service, AgentRunner).
// Durable knobs (Harness, Model, Provider, Effort,
// ContextBudget, MirrorCfg) live on config.ResolvedConfig and are passed
// via ExecuteBeadWithConfig's rcfg argument.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev         string // base git revision (default: HEAD)
	PromptFile      string // override prompt file (auto-generated if empty)
	Output          io.Writer
	WorkerID        string // from DDX_WORKER_ID env or caller
	BeadEvents      BeadEventAppender
	BeadCancel      BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	ResourceChecker ExecutionResourceChecker
	Service         agentlib.FizeauService
	AgentRunner     AgentRunner
	AttemptBackend  AttemptBackend
	// RateLimitMaxWait bounds the per-bead total wait spent on rate-limit
	// retries (ddx-c6e3db02 RateLimitRetryContract / TD-031 §8.4). Zero uses
	// RateLimitRetryDefaultBudget (5 min). Negative disables the wrapper —
	// rate-limit responses fall through to the standard execution_failed path.
	RateLimitMaxWait time.Duration

package agent

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docprose"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	agentlib "github.com/easel/fizeau"
)

// beadStrictnessMode returns the strictness mode for review based on bead
// labels. kind:doc and kind:mechanical → mechanical; kind:refactor and
// kind:chore → behavior-light; default → strict.
func beadStrictnessMode(labels []string) string {
	for _, l := range labels {
		switch l {
		case "kind:doc", "kind:mechanical":
			return StrictnessMechanical
		case "kind:refactor", "kind:chore":
			return StrictnessBehavior
		}
	}
	return StrictnessStrict
}

// strictnessModeInstructions returns the per-mode evidence requirement text
// injected into the reviewer prompt.
func strictnessModeInstructions(mode string) string {
	switch mode {
	case StrictnessMechanical:
		return "mechanical — file presence, renames, or symbol evidence only; no test-name or runtime evidence required."
	case StrictnessBehavior:
		return "behavior-light — build green plus file/symbol evidence suffices; test-name match required only when an AC explicitly names a Test* function."
	default:
		return "strict — each AC must be anchored to a named Test* function or a diff-touched symbol; file-only evidence is insufficient."
	}
}

// ReviewRequestClarificationEventKind is the event kind appended to a bead
// when the reviewer returns REQUEST_CLARIFICATION.
const ReviewRequestClarificationEventKind = "review-request-clarification"

// ReviewPairingDegradedEventKind is the kind:review-pairing-degraded event
// kind appended to the bead when the post-merge reviewer was routed to the
// same provider as the implementer. R4 (different reviewer) is best-effort
// emergent: bumping MinPower usually picks a different candidate, but the
// guarantee is not absolute. The event surfaces the degradation so operators
// can see when reviewer diversity collapsed.
const ReviewPairingDegradedEventKind = "review-pairing-degraded"

// ReviewerEscalatedEventKind is the kind:reviewer-escalated event kind
// appended when the reviewer's MinPower is bumped above the baseline
// impl.ActualPower+1 due to prior review-error or review-pairing-degraded
// events for the same result_rev.
const ReviewerEscalatedEventKind = "reviewer-escalated"

// ReviewACOverrideEventKind is appended when the reviewer's per-AC grade
// contradicts the ac-check.json mechanical result for the same AC item.
// The event records the mismatch count and per-AC reasons for accuracy auditing.
const ReviewACOverrideEventKind = "review-ac-override"

// acCheckOutput is the minimal shape of .ddx/executions/<id>/ac-check.json
// needed for AC-grade mismatch detection.
type acCheckOutput struct {
	Items []struct {
		AC     int    `json:"ac"`
		Result string `json:"result"`
	} `json:"items"`
}

// countACGradeMismatches compares the reviewer's per-AC grades against
// the mechanical results from ac-check.json. Returns the number of mismatches
// (reviewer says pass where ac-check says fail, or vice versa) and a list
// of per-AC reasons. Ignores needs_judgment and error mechanical results.
func countACGradeMismatches(acCheckJSONStr string, perAC []ReviewAC) (int, []string) {
	if acCheckJSONStr == "" || len(perAC) == 0 {
		return 0, nil
	}
	var check acCheckOutput
	if err := json.Unmarshal([]byte(acCheckJSONStr), &check); err != nil {
		return 0, nil
	}
	mechByNum := make(map[int]string, len(check.Items))
	for _, item := range check.Items {
		mechByNum[item.AC] = strings.ToLower(item.Result)
	}
	count := 0
	var reasons []string
	for _, ac := range perAC {
		mech, ok := mechByNum[ac.Number]
		if !ok {
			continue
		}
		// Only compare definitive mechanical verdicts; skip needs_judgment/error.
		if mech != "pass" && mech != "fail" {
			continue
		}
		grade := strings.ToLower(ac.Grade)
		if (mech == "fail" && grade == "pass") || (mech == "pass" && grade == "fail") {
			count++
			reasons = append(reasons, fmt.Sprintf("ac%d: ac_check=%s reviewer=%s", ac.Number, mech, grade))
		}
	}
	return count, reasons
}

// ImplementerRouting captures the implementer's resolved routing details so
// the post-merge reviewer can build a paired ExecuteRequest with Role=reviewer,
// the same correlation, and MinPower bumped one above the implementer's
// actual selected power (R4 pairing).
type ImplementerRouting struct {
	Harness     string
	Provider    string
	Model       string
	ActualPower int
	// Correlation is the implementer's correlation map. The reviewer copies
	// its keys into its own dispatch metadata so events / session log /
	// aggregations can join the two calls.
	Correlation map[string]string
}

// Verdict is the outcome of a post-merge bead review.
type Verdict string

const (
	// VerdictApprove means all AC items passed; the bead stays closed.
	VerdictApprove Verdict = "APPROVE"
	// VerdictRequestChanges means some AC items need fixing; the bead stays open
	// and the pre-close gate records the verdict without closing.
	VerdictRequestChanges Verdict = "REQUEST_CHANGES"
	// VerdictBlock means escalation should stop; the bead is flagged for human
	// review while remaining open.
	VerdictBlock Verdict = "BLOCK"
	// VerdictRequestClarification means the reviewer cannot adjudicate one or
	// more needs-judgment AC items without additional operator context. Unlike
	// BLOCK it does not halt automated retry; it parks the bead to
	// status=proposed so the operator can supply the missing context.
	VerdictRequestClarification Verdict = "REQUEST_CLARIFICATION"
)

// Strictness mode constants drive the per-bead evidence requirements injected
// into the reviewer prompt. The mode is derived from bead labels.
const (
	// StrictnessStrict requires named Test* functions and diff-anchored symbols
	// per AC. Applied to kind:fix and kind:feat beads.
	StrictnessStrict = "strict"
	// StrictnessBehavior requires build-green plus file/symbol evidence.
	// Test-name match is required only when an AC explicitly names a Test*.
	// Applied to kind:refactor and kind:chore beads.
	StrictnessBehavior = "behavior-light"
	// StrictnessMechanical requires only file presence, renames, or symbol
	// evidence. Applied to kind:doc and kind:mechanical beads.
	StrictnessMechanical = "mechanical"
)

// ReviewResult is the structured outcome of a post-merge bead review.
type ReviewResult struct {
	Verdict          Verdict    `json:"verdict"`
	Rationale        string     `json:"rationale,omitempty"`
	PerAC            []ReviewAC `json:"per_ac,omitempty"`
	Findings         []Finding  `json:"findings,omitempty"`
	ProseFindings    []Finding  `json:"prose_findings,omitempty"`
	RawOutput        string     `json:"raw_output,omitempty"`
	ReviewerHarness  string     `json:"reviewer_harness,omitempty"`
	ReviewerModel    string     `json:"reviewer_model,omitempty"`
	ReviewerProvider string     `json:"reviewer_provider,omitempty"`
	ReviewerIndex    int        `json:"reviewer_index,omitempty"`
	SessionID        string     `json:"session_id,omitempty"`
	BaseRev          string     `json:"base_rev,omitempty"`
	ResultRev        string     `json:"result_rev,omitempty"`
	ExecutionDir     string     `json:"execution_dir,omitempty"`
	DurationMS       int        `json:"duration_ms,omitempty"`
	Error            string     `json:"error,omitempty"`
	CostUSD          float64    `json:"cost_usd,omitempty"`
	// InputBytes and OutputBytes are the FEAT-022 §16 byte counters used to
	// populate the compact summary appended to review and review-error event
	// bodies. InputBytes is the assembled prompt size; OutputBytes is the
	// raw reviewer output size (zero on pre-dispatch overflow / transport).
	InputBytes  int `json:"input_bytes,omitempty"`
	OutputBytes int `json:"output_bytes,omitempty"`
}

type ReviewAC struct {
	Number   int    `json:"number"`
	Item     string `json:"item,omitempty"`
	Grade    string `json:"grade,omitempty"`
	Evidence string `json:"evidence,omitempty"`
}

// ReviewGroupBundle identifies the shared evidence bundle used by a
// two-slot review-group dispatch.
type ReviewGroupBundle struct {
	GroupID   string `json:"group_id"`
	DirAbs    string `json:"dir_abs"`
	DirRel    string `json:"dir_rel"`
	PromptAbs string `json:"prompt_abs"`
	PromptRel string `json:"prompt_rel"`
}

// ReviewGroupSlotResult captures one slot's runtime and structured review
// result for a review-group dispatch.
type ReviewGroupSlotResult struct {
	ReviewerIndex int             `json:"reviewer_index"`
	Runtime       AgentRunRuntime `json:"runtime"`
	Result        *ReviewResult   `json:"result,omitempty"`
	Error         string          `json:"error,omitempty"`
}

// ReviewGroupResult is the structured output of a two-slot review-group
// dispatch.
type ReviewGroupResult struct {
	BeadID    string                  `json:"bead_id"`
	ResultRev string                  `json:"result_rev"`
	Bundle    ReviewGroupBundle       `json:"bundle"`
	Slots     []ReviewGroupSlotResult `json:"slots"`
}

// ReviewGroupDispatchMeta identifies a single slot within a review group.
type ReviewGroupDispatchMeta struct {
	GroupID       string
	ReviewerIndex int
}

type reviewerDispatchProfile struct {
	Name     string
	MinPower int
}

type reviewArtifactManifest struct {
	Harness          string                     `json:"harness,omitempty"`
	Model            string                     `json:"model,omitempty"`
	SessionID        string                     `json:"session_id,omitempty"`
	BaseRev          string                     `json:"base_rev,omitempty"`
	ResultRev        string                     `json:"result_rev,omitempty"`
	Verdict          string                     `json:"verdict,omitempty"`
	BeadID           string                     `json:"bead_id,omitempty"`
	ExecutionDir     string                     `json:"execution_dir,omitempty"`
	EvidenceAssembly *EvidenceAssemblyTelemetry `json:"evidence_assembly,omitempty"`
}

type reviewArtifactResult struct {
	Verdict          string                     `json:"verdict"`
	PerAC            []ReviewAC                 `json:"per_ac,omitempty"`
	ProseFindings    []Finding                  `json:"prose_findings,omitempty"`
	Rationale        string                     `json:"rationale,omitempty"`
	Findings         []Finding                  `json:"findings,omitempty"`
	Error            string                     `json:"error,omitempty"`
	EvidenceAssembly *EvidenceAssemblyTelemetry `json:"evidence_assembly,omitempty"`

package agent

import (
	"context"
	"encoding/json"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestEvidenceAssemblyTelemetry covers FEAT-022 §15 for both review and
// grading attempt bundles. The result.json must carry an evidence_assembly
// object whose shape matches EvidenceAssemblySection (Stage A1 contract):
// per-section bytes_included / bytes_omitted / truncation_reason /
// selected_items / omitted_items, plus total input_bytes + output_bytes.
func TestEvidenceAssemblyTelemetry(t *testing.T) {
	t.Run("review", func(t *testing.T) {
		projectRoot := t.TempDir()
		out, err := exec.Command("git", "init", projectRoot).CombinedOutput()
		require.NoError(t, err, string(out))

		store := bead.NewStore(filepath.Join(projectRoot, ddxroot.DirName))
		require.NoError(t, store.Init(context.Background()))
		// Write a governing doc whose body is large enough to be clamped
		// under the small caps used below (forces truncation_reason).
		docRel := "docs/big.md"
		docAbs := filepath.Join(projectRoot, filepath.FromSlash(docRel))
		require.NoError(t, os.MkdirAll(filepath.Dir(docAbs), 0o755))
		require.NoError(t, os.WriteFile(docAbs, []byte(strings.Repeat("X", 8*1024)), 0o644))

		require.NoError(t, store.Create(context.Background(), &bead.Bead{
			ID:          "ddx-evid-telem",
			Title:       "evidence telemetry review fixture",
			Description: "exercise governing doc clamp + diff section",
			Acceptance:  "AC#1: foo handler\nAC#2: bar coverage",
			Notes:       "see docs/big.md",
			Extra:       map[string]any{"spec-id": docRel},
		}))
		out, err = exec.Command("git", "-C", projectRoot, "add", "README.md", "docs/big.md", ".ddx/beads.jsonl").CombinedOutput()
		// README.md may not exist; ignore and just commit what's staged.
		_ = err
		_ = out
		out, err = exec.Command("git", "-C", projectRoot, "add", "-A").CombinedOutput()
		require.NoError(t, err, string(out))
		out, err = exec.Command("git", "-C", projectRoot, "-c", "user.name=Test", "-c", "user.email=test@example.com", "commit", "-m", "init").CombinedOutput()
		require.NoError(t, err, string(out))
		headRaw, err := exec.Command("git", "-C", projectRoot, "rev-parse", "HEAD").Output()
		require.NoError(t, err)
		head := strings.TrimSpace(string(headRaw))

		reviewer := &DefaultBeadReviewer{
			ProjectRoot: projectRoot,
			BeadStore:   store,
			Runner: &reviewRunnerStub{result: &Result{
				Harness:        "claude",
				Model:          "claude-opus-4-6",
				Output:         "```json\n{\"schema_version\":1,\"verdict\":\"APPROVE\",\"summary\":\"ok\"}\n```",
				DurationMS:     17,
				AgentSessionID: "sess-evid-1",
			}},
			Caps: evidence.Caps{
				MaxPromptBytes:       64 * 1024,
				MaxInlinedFileBytes:  4 * 1024,
				MaxDiffBytes:         16 * 1024,
				MaxGoverningDocBytes: 1024, // forces clamp on the 8KiB doc
			},
		}

		res, err := reviewer.ReviewBead(context.Background(), "ddx-evid-telem", head, ImplementerRouting{Harness: "claude", Model: "claude-sonnet"})
		require.NoError(t, err)
		require.NotNil(t, res)
		require.NotEmpty(t, res.ExecutionDir)

		resultPath := filepath.Join(projectRoot, filepath.FromSlash(res.ExecutionDir), "result.json")
		raw, err := os.ReadFile(resultPath)
		require.NoError(t, err)

		var doc map[string]any
		require.NoError(t, json.Unmarshal(raw, &doc))
		ea, ok := doc["evidence_assembly"].(map[string]any)
		require.True(t, ok, "result.json must contain an evidence_assembly object: %s", string(raw))
		// total bytes
		assert.Greater(t, int(ea["input_bytes"].(float64)), 0, "input_bytes must be populated")
		assert.Greater(t, int(ea["output_bytes"].(float64)), 0, "output_bytes must be populated")

		// per-section records
		secsRaw, ok := ea["sections"].([]any)
		require.True(t, ok, "evidence_assembly.sections must be an array")
		require.NotEmpty(t, secsRaw, "expect at least one section record (bead, governing, diff)")

		// At least one section should carry a truncation_reason (the clamped
		// governing doc) and the EvidenceAssemblySection field shape.
		foundClampedGoverning := false
		for _, raw := range secsRaw {
			s, ok := raw.(map[string]any)
			if !ok {
				continue
			}
			// Required field shape: bytes_included / bytes_omitted /
			// truncation_reason / selected_items / omitted_items / name.
			_, hasName := s["name"]
			_, hasIncluded := s["bytes_included"]
			assert.True(t, hasName, "section must carry name")
			assert.True(t, hasIncluded, "section must carry bytes_included")
			if reason, ok := s["truncation_reason"].(string); ok && reason == "governing_doc_cap" {
				foundClampedGoverning = true
			}
		}
		assert.True(t, foundClampedGoverning, "expected a section with truncation_reason=governing_doc_cap")

		// jq-style assertion: evidence_assembly is an object.
		assert.IsType(t, map[string]any{}, doc["evidence_assembly"])

		// Manifest mirrors the same key.
		manifestPath := filepath.Join(projectRoot, filepath.FromSlash(res.ExecutionDir), "manifest.json")
		mraw, err := os.ReadFile(manifestPath)
		require.NoError(t, err)
		var mdoc map[string]any
		require.NoError(t, json.Unmarshal(mraw, &mdoc))
		_, ok = mdoc["evidence_assembly"].(map[string]any)
		assert.True(t, ok, "manifest.json must also carry evidence_assembly")
	})

}

// TestReviewEventBodySummary covers FEAT-022 §16: review, review-error, and
// compare-result event bodies all carry the compact summary fields
// (input_bytes, output_bytes, elapsed_ms, harness, model).
func TestReviewEventBodySummary(t *testing.T) {
	summary := EventBodySummary{
		Harness:     "claude",
		Model:       "claude-opus-4-6",
		InputBytes:  12345,
		OutputBytes: 678,
		ElapsedMS:   42,
	}

	t.Run("review", func(t *testing.T) {
		body := AppendEventSummary(ReviewEventBody("APPROVE", "ok", "path/to/log"), summary)
		assertSummaryFields(t, body, summary)
	})

	t.Run("review-error", func(t *testing.T) {
		body := AppendEventSummary(
			ReviewErrorEventBody(evidence.OutcomeReviewTransport, 1, "abc123", "boom"),
			summary,
		)
		assertSummaryFields(t, body, summary)
		// Crucial: section detail does NOT land on the event body.
		assert.NotContains(t, body, "bytes_included",
			"event body must not carry per-section detail (lives only on the artifact)")
	})

}

func assertSummaryFields(t *testing.T, body string, s EventBodySummary) {
	t.Helper()
	assert.Contains(t, body, "harness="+s.Harness)
	assert.Contains(t, body, "model="+s.Model)
	assert.Contains(t, body, "input_bytes=12345")
	assert.Contains(t, body, "output_bytes=678")
