			for _, ref := range pinnedRefs {
				_ = c.RefStore.UnpinCandidateRef(c.ProjectRoot, ref)
			}
		}
	}

	return result, nil
}

func (c *AttemptCycleCoordinator) recordCandidateCycleState(candidate CandidateResult, state CandidateCycleState) {
	if candidate.WorktreePath == "" {
		return
	}
	_ = WriteWorktreeCandidateCycleState(c.ProjectRoot, candidate.WorktreePath, candidate.Report.AttemptID, state)
}

func candidateChecksFailedDetail(detail string) string {
	detail = strings.TrimSpace(detail)
	if detail == "" {
		return candidateChecksFailedEventKind
	}
	return candidateChecksFailedEventKind + ": " + detail
}

func appendUniqueString(items []string, item string) []string {
	item = strings.TrimSpace(item)
	if item == "" {
		return items
	}
	for _, existing := range items {
		if existing == item {
			return items
		}
	}
	return append(items, item)
}

func (c *AttemptCycleCoordinator) pinCandidateRef(beadID string, candidate *CandidateResult) {
	if candidate == nil || c.RefStore == nil || c.ProjectRoot == "" {
		return
	}
	if candidate.Report.CandidateRef != "" {
		return
	}
	ref, pinErr := c.RefStore.PinCandidateRef(
		c.ProjectRoot,
		candidate.Report.AttemptID,
		candidate.CycleIndex,
		candidate.Report.ResultRev,
	)
	if pinErr != nil {
		return
	}
	candidate.Report.CandidateRef = ref
	candidate.Report.CycleIndex = candidate.CycleIndex
	if c.BeadEvents == nil {
		return
	}
	body, _ := json.Marshal(CandidateCycleEventBody{
		CandidateRef: ref,
		CycleIndex:   candidate.CycleIndex,
		AttemptID:    candidate.Report.AttemptID,
		BaseRev:      candidate.Report.BaseRev,
		ResultRev:    candidate.Report.ResultRev,
	})
	_ = c.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
		Kind: "candidate_cycle_pinned",
		Body: string(body),
	})
}

func (c *AttemptCycleCoordinator) appendCandidateChecksFailedEvent(beadID string, report ExecuteBeadReport, checksResult CandidateCheckResult) {
	if c.BeadEvents == nil {
		return
	}
	body, _ := json.Marshal(CandidateChecksFailedEventBody{
		CandidateRef: report.CandidateRef,
		CycleIndex:   report.CycleIndex,
		AttemptID:    report.AttemptID,
		BaseRev:      report.BaseRev,
		ResultRev:    report.ResultRev,
		Detail:       strings.TrimSpace(checksResult.Detail),
		Artifacts:    append([]string(nil), checksResult.Artifacts...),
	})
	_ = c.BeadEvents.AppendEvent(beadID, bead.BeadEvent{
		Kind:    candidateChecksFailedEventKind,
		Summary: report.Detail,
		Body:    string(body),
	})
}

func (c *AttemptCycleCoordinator) maxRepairCycles() int {
	if c.RepairMaxCycles <= 0 {
		return 1
	}
	return c.RepairMaxCycles
}

func (c *AttemptCycleCoordinator) classifyCandidateReview(review CandidateReviewResult) ReviewFindingClassification {
	if review.Classification != "" {
		return reviewClassification(review.Classification, nil, "", review.Classification == ReviewFindingClassFixableGap)
	}

func TestExecuteBeadWorkerReviewSkipLabelWithoutReasonIsIgnored(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	labeled := &bead.Bead{ID: "ddx-skip-2", Title: "Skip review", Labels: []string{"review:skip"}}
	require.NoError(t, store.Create(context.Background(), labeled))

	reviewerCalled := false
	reviewer := beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
		reviewerCalled = true
		return &ReviewResult{Verdict: VerdictRequestChanges}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	out := RunPostMergeReview(context.Background(), PostMergeReviewInput{
		Bead: *labeled,
		Report: ExecuteBeadReport{
			BeadID:    labeled.ID,
			Status:    ExecuteBeadStatusSuccess,
			SessionID: "sess-label-ignore",
			ResultRev: "feedface",
		},
		Reviewer:    reviewer,
		Store:       store,
		ProjectRoot: t.TempDir(),
		Rcfg:        rcfg,
		Now:         time.Now,
		Assignee:    "worker",
	})
	require.False(t, out.Approved)
	assert.True(t, reviewerCalled, "reviewer must be called when review:skip lacks a review:skip-reason label")
	assert.Equal(t, ExecuteBeadStatusReviewRequestChanges, out.Report.Status)

	got, err := store.Get(context.Background(), labeled.ID)
	require.NoError(t, err)
	assert.NotEqual(t, bead.StatusClosed, got.Status, "label-only skip should be ignored")
}

func TestExecuteBeadWorker_NiflheimEvidence_EmptyReviewResultCannotClose(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-empty-review",
				ResultRev: "badc0ffe",
				CycleTrace: []ExecutionCycleTrace{
					{
						CycleIndex:    0,
						AttemptID:     "attempt-empty-review",
						ResultRev:     "badc0ffe",
						ReviewGroupID: "rg-empty-review",
						ReviewerIndices: []int{
							0,
						},
						ReviewVerdicts: []string{
							"APPROVE",
						},
						ReviewResult:  ExecutionCycleReviewResult{},
						FinalDecision: ExecuteBeadStatusSuccess,
					},
				},
			}, nil
		}),
		Reviewer: beadReviewerFunc(func(_ context.Context, _, _ string, _ ImplementerRouting) (*ReviewResult, error) {
			return &ReviewResult{Verdict: VerdictApprove}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	assert.Equal(t, 0, result.Successes)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, ExecuteBeadStatusReviewMalfunction, result.LastFailureStatus)

	got, err := store.Get(context.Background(), first.ID)
	require.NoError(t, err)
	assert.NotEqual(t, bead.StatusClosed, got.Status)

	events, err := store.Events(first.ID)
	require.NoError(t, err)
	var reviewError *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "review-error" {
			reviewError = &events[i]
			break
		}
	}
	require.NotNil(t, reviewError, "empty review result must emit review-error evidence")
	assert.NotEmpty(t, reviewError.Body)
	assert.Contains(t, reviewError.Body, "empty review result before close")
}

