func classifyDecisionFailureClass(report ExecuteBeadReport) string {
	if s := strings.TrimSpace(report.FailureClass); s != "" {
		return s
	}
	if s := strings.TrimSpace(report.OutcomeReason); s != "" {
		return s
	}
	if s := strings.TrimSpace(report.FailureMode); s != "" {
		return s
	}
	if s := strings.TrimSpace(report.Status); s != "" {
		return s
	}
	return strings.TrimSpace(report.OrchestratorStatus)
}

func classifyDecisionRetryAction(report ExecuteBeadReport) string {
	if s := strings.TrimSpace(report.RetryAction); s != "" {
		return s
	}
	if strings.TrimSpace(report.ReconcileStatus) != "" {
		return "reconcile"
	}
	switch {
	case report.Status == ExecuteBeadStatusSuccess || report.LandStatus == "landed":
		return "close"
	case strings.TrimSpace(report.LandStatus) == "error":
		return "retry"
	case strings.TrimSpace(report.LandStatus) == "preserved":
		return "park"
	case strings.Contains(strings.ToLower(report.LandStatus), "park"):
		return "park"
	case strings.TrimSpace(report.ReviewStatus) == "skipped":
		return "close"
	case strings.TrimSpace(report.ReviewStatus) == "error":
		return "retry"
	case strings.TrimSpace(report.ReviewStatus) == "malformed":
		return "retry"
	case report.Status == ExecuteBeadStatusReviewRequestClarification:
		return "park"
	}
	switch classifyDecisionFailureClass(report) {
	case "operator_attention":
		return "park"
	case FailureModeRouteResolutionTimeout, FailureModeProgressWatchdog, FailureModeConsecutiveWedge,
		FailureModeLandOperatorAttention, FailureModeWorktreeLost:
		return "park"
	case FailureModeLandRetry, FailureModeLockContention, FailureModeProviderConnectivity,
		FailureModeNoViableProvider, FailureModeServerUnavailable, FailureModeTimeout,
		FailureModeNoEvidenceProduced, FailureModeNoChanges, FailureModeAttemptIntegrity,
		FailureModeContextOverflow, FailureModeAuthError, FailureModeBuildFailure,
		FailureModeTestFailure, FailureModeUnknown:
		return "retry"
	}
	if strings.TrimSpace(report.FinalPowerClass) != "" && strings.TrimSpace(report.ReviewStatus) != "" {
		return "review"
	}
	if strings.TrimSpace(report.FailureClass) == "decomposed" || strings.Contains(strings.ToLower(report.Detail), "decomposed") {
		return "decompose"
	}
	return "retry"
}

